1	// 代理流量列表 + 单请求详情（lazy load）。
2	import { useEffect, useRef, useState } from "react";
3	
4	const T = {
5	  title:          { zh: "代理流量", en: "Proxy Traffic" },
6	  live:           { zh: "实时", en: "Live" },
7	  paused:         { zh: "已暂停", en: "Paused" },
8	  noData:         { zh: "暂无流量记录", en: "No traffic yet" },
9	  category:       { zh: "类别", en: "Category" },
10	  method:         { zh: "方法", en: "Method" },
11	  status:         { zh: "状态", en: "Status" },
12	  path:           { zh: "路径", en: "Path" },
13	  duration:       { zh: "耗时", en: "Duration" },
14	  size:           { zh: "大小", en: "Size" },
15	  reqHeaders:     { zh: "请求头", en: "Request Headers" },
16	  resHeaders:     { zh: "响应头", en: "Response Headers" },
17	  reqBody:        { zh: "请求体（明文）", en: "Request Body (plaintext)" },
18	  resBody:        { zh: "响应体（明文）", en: "Response Body (plaintext)" },
19	  loading:        { zh: "加载中…", en: "Loading…" },
20	  loadBody:       { zh: "点击展开", en: "Click to expand" },
21	  sync:           { zh: "同步", en: "Sync" },
22	  syncing:        { zh: "同步中…", en: "Syncing…" },
23	  filterAll:      { zh: "全部", en: "All" },
24	  captureTargets: { zh: "拦截目标", en: "Capture Targets" },
25	  addHost:        { zh: "添加主机", en: "Add Host" },
26	  removeHost:     { zh: "移除", en: "Remove" },
27	  saveTargets:    { zh: "保存", en: "Save" },
28	  targetsSaved:   { zh: "已生效，无需重启", en: "Applied, no restart needed" },
29	};
30	
31	type Lang = "zh" | "en";
32	function getLang(): Lang { return localStorage.getItem("lang") === "en" ? "en" : "zh"; }
33	function t(key: keyof typeof T, lang: Lang): string { return T[key][lang]; }
34	
35	// ── 请求分类 ──────────────────────────────────────────────────────────────────
36	
37	type Category = "llm" | "auth" | "telemetry" | "mcp" | "other";
38	
39	interface CategoryMeta {
40	  label: { zh: string; en: string };
41	  color: string;
42	  bg: string;
43	}
44	
45	const CATEGORY_META: Record<Category, CategoryMeta> = {
46	  llm:       { label: { zh: "LLM 推理", en: "LLM"       }, color: "#7c3aed", bg: "#f5f0ff" },
47	  auth:      { label: { zh: "认证",     en: "Auth"      }, color: "#0369a1", bg: "#e0f2fe" },
48	  telemetry: { label: { zh: "遥测",     en: "Telemetry" }, color: "#92400e", bg: "#fef3c7" },
49	  mcp:       { label: { zh: "MCP",      en: "MCP"       }, color: "#065f46", bg: "#d1fae5" },
50	  other:     { label: { zh: "其他",     en: "Other"     }, color: "#555",    bg: "#f0f0f0" },
51	};
52	
53	function classifyRequest(url: string, sni: string): Category {
54	  const u = url.toLowerCase();
55	  // LLM 推理：/v1/messages、/v1/complete、count_tokens
56	  if (/\/v1\/messages|\/v1\/complete|count_tokens/.test(u)) return "llm";
57	  // 认证：oauth、create_api_key、platform.claude.com/oauth
58	  if (/oauth|api_key|platform\.claude\.com/.test(u)) return "auth";
59	  // 遥测：metrics、sentry、statsig、amplitude、telemetry
60	  if (/metrics|sentry|statsig|amplitude|telemetry/.test(u)) return "telemetry";
61	  // MCP：mcp-proxy、mcp-registry、/v1/mcp/
62	  if (/mcp/.test(u) || /mcp/.test(sni.toLowerCase())) return "mcp";
63	  return "other";
64	}
65	
66	// ── 数据结构 ──────────────────────────────────────────────────────────────────
67	
68	interface ProxyRequest {
69	  id: number;
70	  ts: string;
71	  started_at?: string;
72	  sni: string;
73	  method: string;
74	  url: string;
75	  status: number | null;
76	  bytes_in: number;
77	  bytes_out: number;
78	  duration_ms: number | null;
79	  req_headers: Record<string, string> | string;
80	  res_headers: Record<string, string> | string;
81	  req_body: string;
82	  res_body: string;
83	  sse_event_count: number;
84	  is_stream: number | boolean;
85	}
86	
87	function parseHeaders(h: Record<string, string> | string): Record<string, string> {
88	  if (typeof h === "string") { try { return JSON.parse(h); } catch { return {}; } }
89	  return h ?? {};
90	}
91	
92	function formatBytes(n: number): string {
93	  if (!n) return "—";
94	  if (n < 1024) return `${n} B`;
95	  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
96	  return `${(n / 1024 / 1024).toFixed(2)} MB`;
97	}
98	
99	function statusColor(s: number | null): string {
100	  if (!s) return "#999";
101	  if (s < 300) return "#34c759";
102	  if (s < 400) return "#ff9f0a";
103	  return "#ff3b30";
104	}
105	
106	function pathFromUrl(url: string): string {
107	  try { return new URL(url).pathname; } catch { return url; }
108	}
109	
110	function requestStartedAt(req: ProxyRequest): string {
111	  return req.started_at || req.ts;
112	}
113	
114	function mergeRequests(prev: ProxyRequest[], incoming: ProxyRequest[]): ProxyRequest[] {
115	  const byId = new Map<number, ProxyRequest>();
116	  for (const req of prev) byId.set(req.id, req);
117	  for (const req of incoming) byId.set(req.id, req);
118	  return [...byId.values()]
119	    .sort((a, b) => {
120	      const byStartedAt = requestStartedAt(b).localeCompare(requestStartedAt(a));
121	      return byStartedAt !== 0 ? byStartedAt : b.id - a.id;
122	    })
123	    .slice(0, 500);
124	}
125	
126	// ── 懒加载消息体 ──────────────────────────────────────────────────────────────
127	
128	function LazyBody({ value, lang }: { value: string; lang: Lang }) {
129	  const [open, setOpen] = useState(false);
130	
131	  if (!value || value === "") return <span style={{ color: "#ccc", fontSize: 12 }}>—</span>;
132	
133	  // 流式占位符直接展示，不折叠
134	  if (value.startsWith("[sse ") || value.startsWith("[stream ") || value.startsWith("[truncated ") || value.startsWith("[binary ")) {
135	    return <span style={{ color: "#999", fontSize: 12 }}>{value}</span>;
136	  }
137	
138	  if (!open) {
139	    // 预览前 80 字符
140	    const preview = value.length > 80 ? value.slice(0, 80) + "…" : value;
141	    return (
142	      <button
143	        onClick={() => setOpen(true)}
144	        style={{ background: "none", border: "none", padding: 0, cursor: "pointer", textAlign: "left", width: "100%" }}
145	      >
146	        <span style={{ fontSize: 11, color: "#999", fontFamily: "monospace" }}>{preview}</span>
147	        <span style={{ marginLeft: 6, fontSize: 10, color: "#007aff" }}>{t("loadBody", lang)}</span>
148	      </button>
149	    );
150	  }
151	
152	  let pretty = value;
153	  try { pretty = JSON.stringify(JSON.parse(value), null, 2); } catch { void 0; }
154	
155	  return (
156	    <div>
157	      <button onClick={() => setOpen(false)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 11, color: "#999", marginBottom: 4, padding: 0 }}>
158	        ▲ 收起
159	      </button>
160	      <pre style={{
161	        background: "#1a1a1a", color: "#e8e8e8", borderRadius: 6,
162	        padding: "10px 12px", fontSize: 11, overflow: "auto",
163	        maxHeight: 400, margin: 0, whiteSpace: "pre-wrap", wordBreak: "break-all",
164	        fontFamily: "monospace",
165	      }}>
166	        {pretty}
167	      </pre>
168	    </div>
169	  );
170	}
171	
172	// ── 单请求详情抽屉 ────────────────────────────────────────────────────────────
173	
174	function RequestDetail({ req, lang, onClose }: { req: ProxyRequest; lang: Lang; onClose: () => void }) {
175	  const reqHeaders = parseHeaders(req.req_headers);
176	  const resHeaders = parseHeaders(req.res_headers);
177	  const cat = classifyRequest(req.url, req.sni);
178	  const catMeta = CATEGORY_META[cat];
179	
180	  return (
181	    <div style={{
182	      position: "fixed", top: 0, right: 0, bottom: 0, width: "min(640px, 100vw)",
183	      background: "#fff", boxShadow: "-4px 0 32px rgba(0,0,0,0.14)",
184	      zIndex: 1000, display: "flex", flexDirection: "column",
185	    }}>
186	      {/* 固定头部 */}
187	      <div style={{ padding: "16px 20px", borderBottom: "1px solid #f0f0f0", flexShrink: 0 }}>
188	        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
189	          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
190	            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
191	              <span style={{ fontWeight: 700, fontSize: 15 }}>{req.method}</span>
192	              <span style={{ color: statusColor(req.status), fontWeight: 600, fontSize: 15 }}>{req.status ?? "—"}</span>
193	              <span style={{
194	                fontSize: 11, padding: "2px 7px", borderRadius: 10,
195	                background: catMeta.bg, color: catMeta.color, fontWeight: 600,
196	              }}>
197	                {catMeta.label[lang]}
198	              </span>
199	              {(req.is_stream === 1 || req.is_stream === true) && (
200	                <span style={{ fontSize: 10, padding: "2px 6px", borderRadius: 10, background: "#f0f0f0", color: "#666" }}>SSE</span>
201	              )}
202	            </div>
203	            <div style={{ fontSize: 12, color: "#666", wordBreak: "break-all" }}>{req.url}</div>
204	            <div style={{ fontSize: 11, color: "#999" }}>
205	              {requestStartedAt(req)} · {req.duration_ms != null ? `${req.duration_ms}ms` : "—"} · {formatBytes(req.bytes_out || req.bytes_in)}
206	              {req.sse_event_count > 0 && ` · ${req.sse_event_count} SSE events`}
207	            </div>
208	          </div>
209	          <button onClick={onClose} style={{ border: "none", background: "none", cursor: "pointer", fontSize: 22, color: "#999", flexShrink: 0, marginLeft: 12 }}>✕</button>
210	        </div>
211	      </div>
212	
213	      {/* 滚动内容区 */}
214	      <div style={{ flex: 1, overflow: "auto", padding: "16px 20px", display: "flex", flexDirection: "column", gap: 16 }}>
215	        <DetailSection title={t("reqHeaders", lang)}>
216	          <HeaderTable headers={reqHeaders} />
217	        </DetailSection>
218	
219	        <DetailSection title={t("reqBody", lang)}>
220	          <LazyBody value={req.req_body} lang={lang} />
221	        </DetailSection>
222	
223	        <DetailSection title={t("resHeaders", lang)}>
224	          <HeaderTable headers={resHeaders} />
225	        </DetailSection>
226	
227	        <DetailSection title={t("resBody", lang)}>
228	          <LazyBody value={req.res_body} lang={lang} />
229	        </DetailSection>
230	      </div>
231	    </div>
232	  );
233	}
234	
235	function DetailSection({ title, children }: { title: string; children: React.ReactNode }) {
236	  return (
237	    <div>
238	      <div style={{ fontWeight: 600, fontSize: 11, color: "#999", textTransform: "uppercase", letterSpacing: "0.05em", marginBottom: 8 }}>{title}</div>
239	      {children}
240	    </div>
241	  );
242	}
243	
244	function HeaderTable({ headers }: { headers: Record<string, string> }) {
245	  const entries = Object.entries(headers);
246	  if (!entries.length) return <span style={{ color: "#ccc", fontSize: 12 }}>—</span>;
247	  return (
248	    <table style={{ width: "100%", fontSize: 12, borderCollapse: "collapse" }}>
249	      <tbody>
250	        {entries.map(([k, v]) => (
251	          <tr key={k} style={{ borderBottom: "1px solid #f5f5f5" }}>
252	            <td style={{ padding: "3px 10px 3px 0", color: "#888", whiteSpace: "nowrap", verticalAlign: "top", width: 1 }}>{k}</td>
253	            <td style={{ padding: "3px 0", wordBreak: "break-all", color: "#333" }}>{v}</td>
254	          </tr>
255	        ))}
256	      </tbody>
257	    </table>
258	  );
259	}
260	
261	// ── Capture Targets ───────────────────────────────────────────────────────────
262	
263	function CaptureTargets({ lang, onSaved }: { lang: Lang; onSaved: () => void }) {
264	  const [hosts, setHosts] = useState<string[]>([]);
265	  const [newHost, setNewHost] = useState("");
266	  const [saving, setSaving] = useState(false);
267	  const [saved, setSaved] = useState(false);
268	
269	  useEffect(() => {
270	    fetch("/api/proxy/whitelist").then((r) => r.json()).then((d) => setHosts(d.user ?? [])).catch(() => {});
271	  }, []);
272	
273	  const save = async () => {
274	    setSaving(true);
275	    try {
276	      await fetch("/api/proxy/whitelist", {
277	        method: "POST", headers: { "Content-Type": "application/json" },
278	        body: JSON.stringify({ hosts }),
279	      });
280	      setSaved(true); setTimeout(() => setSaved(false), 3000); onSaved();
281	    } catch { void 0; }
282	    setSaving(false);
283	  };
284	
285	  const addHost = () => {
286	    const h = newHost.trim();
287	    if (!h || hosts.includes(h)) return;
288	    setHosts([...hosts, h]); setNewHost("");
289	  };
290	
291	  return (
292	    <div style={{ background: "#fff", borderRadius: 10, padding: "14px 18px", border: "1px solid #e5e5e5" }}>
293	      <div style={{ fontWeight: 600, marginBottom: 10, fontSize: 14 }}>{t("captureTargets", lang)}</div>
294	      <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 10 }}>
295	        <HostChip label="api.anthropic.com" removable={false} />
296	        {hosts.map((h) => (
297	          <HostChip key={h} label={h} removable onRemove={() => setHosts(hosts.filter((x) => x !== h))} />
298	        ))}
299	      </div>
300	      <div style={{ display: "flex", gap: 8 }}>
301	        <input
302	          value={newHost} onChange={(e) => setNewHost(e.target.value)}
303	          onKeyDown={(e) => e.key === "Enter" && addHost()}
304	          placeholder="127.0.0.1:8742 / my-gw.example.com"
305	          style={{ flex: 1, padding: "6px 10px", borderRadius: 6, border: "1px solid #ddd", fontSize: 13 }}
306	        />
307	        <button onClick={addHost} style={{ padding: "6px 12px", borderRadius: 6, border: "1px solid #ddd", background: "#f5f5f7", cursor: "pointer", fontSize: 13 }}>
308	          {t("addHost", lang)}
309	        </button>
310	        <button onClick={save} disabled={saving} style={{ padding: "6px 14px", borderRadius: 6, border: "none", background: "#007aff", color: "#fff", cursor: "pointer", fontSize: 13, fontWeight: 600 }}>
311	          {saving ? "…" : t("saveTargets", lang)}
312	        </button>
313	      </div>
314	      {saved && <div style={{ marginTop: 6, fontSize: 12, color: "#34c759" }}>{t("targetsSaved", lang)}</div>}
315	    </div>
316	  );
317	}
318	
319	function HostChip({ label, removable, onRemove }: { label: string; removable: boolean; onRemove?: () => void }) {
320	  return (
321	    <div style={{
322	      display: "inline-flex", alignItems: "center", gap: 4,
323	      padding: "3px 10px", borderRadius: 20,
324	      background: removable ? "#f0f4ff" : "#f5f5f7",
325	      border: `1px solid ${removable ? "#c7d7ff" : "#e0e0e0"}`,
326	      fontSize: 12, color: removable ? "#2563eb" : "#666",
327	    }}>
328	      {label}
329	      {removable && onRemove && (
330	        <button onClick={onRemove} style={{ background: "none", border: "none", cursor: "pointer", color: "#999", fontSize: 14, padding: 0, lineHeight: 1 }}>×</button>
331	      )}
332	    </div>
333	  );
334	}
335	
336	// ── 分类过滤 tab ──────────────────────────────────────────────────────────────
337	
338	function CategoryTabs({ active, counts, lang, onChange }: {
339	  active: Category | "all";
340	  counts: Record<string, number>;
341	  lang: Lang;
342	  onChange: (c: Category | "all") => void;
343	}) {
344	  const tabs: Array<{ id: Category | "all"; label: string; color?: string }> = [
345	    { id: "all",       label: t("filterAll", lang) },
346	    { id: "llm",       label: CATEGORY_META.llm.label[lang],       color: CATEGORY_META.llm.color },
347	    { id: "auth",      label: CATEGORY_META.auth.label[lang],      color: CATEGORY_META.auth.color },
348	    { id: "telemetry", label: CATEGORY_META.telemetry.label[lang], color: CATEGORY_META.telemetry.color },
349	    { id: "mcp",       label: CATEGORY_META.mcp.label[lang],       color: CATEGORY_META.mcp.color },
350	    { id: "other",     label: CATEGORY_META.other.label[lang],     color: CATEGORY_META.other.color },
351	  ];
352	
353	  return (
354	    <div style={{ display: "flex", gap: 4, flexWrap: "wrap" }}>
355	      {tabs.map(({ id, label, color }) => {
356	        const cnt = counts[id] ?? 0;
357	        const isActive = active === id;
358	        return (
359	          <button key={id} onClick={() => onChange(id)} style={{
360	            padding: "4px 10px", borderRadius: 20, border: "1.5px solid",
361	            borderColor: isActive ? (color ?? "#007aff") : "#e0e0e0",
362	            background: isActive ? (color ?? "#007aff") : "#fff",
363	            color: isActive ? "#fff" : (color ?? "#555"),
364	            cursor: "pointer", fontSize: 12, fontWeight: isActive ? 600 : 400,
365	            display: "flex", alignItems: "center", gap: 5,
366	          }}>
367	            {label}
368	            {cnt > 0 && (
369	              <span style={{
370	                background: isActive ? "rgba(255,255,255,0.3)" : "#f0f0f0",
371	                color: isActive ? "#fff" : "#666",
372	                borderRadius: 10, padding: "0 5px", fontSize: 10, fontWeight: 600,
373	              }}>{cnt}</span>
374	            )}
375	          </button>
376	        );
377	      })}
378	    </div>
379	  );
380	}
381	
382	// ── 主组件 ────────────────────────────────────────────────────────────────────
383	
384	export function ProxyTraffic() {
385	  const lang = getLang();
386	  const [requests, setRequests] = useState<ProxyRequest[]>([]);
387	  const [selected, setSelected] = useState<ProxyRequest | null>(null);
388	  const [live, setLive] = useState(true);
389	  const [syncing, setSyncing] = useState(false);
390	  const [catFilter, setCatFilter] = useState<Category | "all">("all");
391	  const [trafficReady, setTrafficReady] = useState(false);
392	  const evtRef = useRef<EventSource | null>(null);
393	  const streamCursorRef = useRef<{ startedAt: string; id: number }>({ startedAt: "", id: 0 });
394	
395	  useEffect(() => {
396	    fetch("/api/proxy/requests?limit=100")
397	      .then((r) => r.json())
398	      .then((d) => {
399	        const initial = (d.requests ?? []) as ProxyRequest[];
400	        setRequests(initial);
401	        const newest = initial[0];
402	        const maxId = initial.reduce((max, req) => Math.max(max, req.id), 0);
403	        streamCursorRef.current = newest
404	          ? { startedAt: requestStartedAt(newest), id: maxId }
405	          : { startedAt: new Date().toISOString(), id: 0 };
406	        setTrafficReady(true);
407	      })
408	      .catch(() => setTrafficReady(true));
409	  }, []);
410	
411	  useEffect(() => {
412	    if (!trafficReady) return;
413	    if (!live) { evtRef.current?.close(); evtRef.current = null; return; }
414	    const cursor = streamCursorRef.current;
415	    const params = new URLSearchParams();
416	    if (cursor.id) params.set("since_id", String(cursor.id));
417	    const streamUrl = `/api/proxy/stream${params.size > 0 ? `?${params.toString()}` : ""}`;
418	    const es = new EventSource(streamUrl);
419	    evtRef.current = es;
420	    es.onmessage = (e) => {
421	      try {
422	        const rec: ProxyRequest = JSON.parse(e.data);
423	        const current = streamCursorRef.current;
424	        if (rec.id > current.id) {
425	          streamCursorRef.current = { startedAt: requestStartedAt(rec), id: rec.id };
426	        }
427	        setRequests((prev) => mergeRequests(prev, [rec]));
428	      } catch { void 0; }
429	    };
430	    return () => { es.close(); evtRef.current = null; };
431	  }, [live, trafficReady]);
432	
433	  const handleSync = async () => {
434	    setSyncing(true);
435	    try {
436	      await fetch("/api/proxy/sync", { method: "POST" });
437	      const d = await fetch("/api/proxy/requests?limit=100").then((r) => r.json());
438	      const next = (d.requests ?? []) as ProxyRequest[];
439	      setRequests(next);
440	      const newest = next[0];
441	      const maxId = next.reduce((max, req) => Math.max(max, req.id), 0);
442	      if (newest) streamCursorRef.current = { startedAt: requestStartedAt(newest), id: maxId };
443	    } catch { void 0; }
444	    setSyncing(false);
445	  };
446	
447	  // 分类计数
448	  const counts = requests.reduce<Record<string, number>>((acc, r) => {
449	    const c = classifyRequest(r.url, r.sni);
450	    acc[c] = (acc[c] ?? 0) + 1;
451	    acc.all = (acc.all ?? 0) + 1;
452	    return acc;
453	  }, {});
454	
455	  const filtered = catFilter === "all" ? requests : requests.filter((r) => classifyRequest(r.url, r.sni) === catFilter);
456	
457	  return (
458	    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
459	      <CaptureTargets lang={lang} onSaved={() => {}} />
460	
461	      <div style={{ background: "#fff", borderRadius: 10, border: "1px solid #e5e5e5", overflow: "hidden" }}>
462	        {/* 工具栏 */}
463	        <div style={{ padding: "12px 16px", borderBottom: "1px solid #f0f0f0", display: "flex", flexDirection: "column", gap: 10 }}>
464	          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
465	            <span style={{ fontWeight: 600, fontSize: 15, flex: 1 }}>{t("title", lang)}</span>
466	            <button onClick={() => setLive((v) => !v)} style={{
467	              padding: "4px 10px", borderRadius: 6, border: "1px solid",
468	              borderColor: live ? "#34c759" : "#ddd",
469	              background: live ? "#f0fff4" : "#f5f5f7",
470	              color: live ? "#34c759" : "#666", cursor: "pointer", fontSize: 12,
471	            }}>
472	              {live ? `● ${t("live", lang)}` : t("paused", lang)}
473	            </button>
474	            <button onClick={handleSync} disabled={syncing} style={{ padding: "4px 10px", borderRadius: 6, border: "1px solid #ddd", background: "#f5f5f7", cursor: "pointer", fontSize: 12 }}>
475	              {syncing ? t("syncing", lang) : t("sync", lang)}
476	            </button>
477	          </div>
478	          {/* 分类过滤 */}
479	          <CategoryTabs active={catFilter} counts={counts} lang={lang} onChange={setCatFilter} />
480	        </div>
481	
482	        {/* 列表 */}
483	        {filtered.length === 0 ? (
484	          <div style={{ padding: 32, textAlign: "center", color: "#999", fontSize: 13 }}>{t("noData", lang)}</div>
485	        ) : (
486	          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
487	            <thead>
488	              <tr style={{ background: "#fafafa" }}>
489	                <th style={thStyle}>{t("category", lang)}</th>
490	                <th style={thStyle}>{t("method", lang)}</th>
491	                <th style={thStyle}>{t("status", lang)}</th>
492	                <th style={{ ...thStyle, width: "99%" }}>{t("path", lang)}</th>
493	                <th style={thStyle}>{t("duration", lang)}</th>
494	                <th style={thStyle}>{t("size", lang)}</th>
495	              </tr>
496	            </thead>
497	            <tbody>
498	              {filtered.map((r) => {
499	                const cat = classifyRequest(r.url, r.sni);
500	                const meta = CATEGORY_META[cat];
501	                return (
502	                  <tr
503	                    key={r.id}
504	                    onClick={() => setSelected(r)}
505	                    style={{ cursor: "pointer", borderBottom: "1px solid #f5f5f5" }}
506	                    onMouseEnter={(e) => (e.currentTarget.style.background = "#fafafa")}
507	                    onMouseLeave={(e) => (e.currentTarget.style.background = "")}
508	                  >
509	                    <td style={tdStyle}>
510	                      <span style={{
511	                        fontSize: 10, padding: "2px 7px", borderRadius: 10,
512	                        background: meta.bg, color: meta.color, fontWeight: 600, whiteSpace: "nowrap",
513	                      }}>
514	                        {meta.label[lang]}
515	                      </span>
516	                    </td>
517	                    <td style={tdStyle}>
518	                      <span style={{ fontWeight: 600, color: "#007aff" }}>{r.method}</span>
519	                    </td>
520	                    <td style={tdStyle}>
521	                      <span style={{ color: statusColor(r.status), fontWeight: 600 }}>{r.status ?? "—"}</span>
522	                      {(r.is_stream === 1 || r.is_stream === true) && (
523	                        <span style={{ marginLeft: 4, fontSize: 10, color: "#7c3aed", background: "#f5f0ff", borderRadius: 3, padding: "1px 4px" }}>SSE</span>
524	                      )}
525	                    </td>
526	                    <td style={{ ...tdStyle, maxWidth: 0, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
527	                      <span style={{ color: "#555" }}>{r.sni}</span>
528	                      <span style={{ color: "#999", marginLeft: 4 }}>{pathFromUrl(r.url)}</span>
529	                    </td>
530	                    <td style={{ ...tdStyle, whiteSpace: "nowrap" }}>{r.duration_ms != null ? `${r.duration_ms}ms` : "—"}</td>
531	                    <td style={{ ...tdStyle, whiteSpace: "nowrap" }}>{formatBytes(r.bytes_out || r.bytes_in)}</td>
532	                  </tr>
533	                );
534	              })}
535	            </tbody>
536	          </table>
537	        )}
538	      </div>
539	
540	      {selected && <RequestDetail req={selected} lang={lang} onClose={() => setSelected(null)} />}
541	    </div>
542	  );
543	}
544	
545	const thStyle: React.CSSProperties = { padding: "7px 12px", textAlign: "left", fontWeight: 600, fontSize: 11, color: "#888", whiteSpace: "nowrap" };
546	const tdStyle: React.CSSProperties = { padding: "8px 12px" };
