17	}
18	
19	const debug = process.env.API_DASHBOARD_PROXY_DEBUG ? (...args: unknown[]) => console.error("[mitm]", ...args) : () => {};
20	
21	// 模块级统计（供 /_health 和 B3.2 连续失败检测使用）
22	let _requestCount = 0;
23	let _startTime = 0;
24	let _listenPort = 0;
25	let _consecutiveFailures = 0;
26	const UPSTREAM_WARN_THRESHOLD = 5;
27	
28	function recordUpstreamSuccess() { _consecutiveFailures = 0; }
29	function recordUpstreamFailure(sni: string, reason: string) {
30	  _consecutiveFailures++;
31	  if (_consecutiveFailures >= UPSTREAM_WARN_THRESHOLD) {
32	    writeTraffic({
33	      ts: new Date().toISOString(),
34	      kind: "event",
35	      msg: "upstream_consecutive_failures",
36	      sni,
37	      meta: { count: _consecutiveFailures, reason },
38	    });
39	  }
40	}
41	
42	export async function startProxy(opts: StartOptions): Promise<{ close: () => Promise<void> }> {
43	  await ensureCa();
44	  _startTime = Date.now();
45	  _requestCount = 0;
46	  _consecutiveFailures = 0;
47	
48	  // 内部 http.Server：消费"已解密的 TLSSocket"上的 HTTP/1.1 流量。
49	  // 必须 listen 一下（端口随机、仅本机）让其内部的 'connection' 事件机制启用，再通过 emit 接收外部 socket。
50	  const httpServer = http.createServer(handleMitmRequest);
51	  httpServer.on("clientError", (e: Error) => debug("internal clientError:", e.message));
52	  await new Promise<void>((res) => httpServer.listen(0, "127.0.0.1", () => res()));
53	
54	  // 主入口：标准 HTTP 代理协议。
55	  const proxy = http.createServer((req, res) => {
56	    // B3.1: /_health 端点
57	    if (req.url === "/_health" && req.method === "GET") {
58	      const upstream = process.env.API_DASHBOARD_PROXY_UPSTREAM;
59	      res.writeHead(200, { "Content-Type": "application/json" });
60	      res.end(JSON.stringify({
61	        ok: true,
62	        listening: true,
63	        upstream: upstream ? "configured" : "none",
64	        pid: process.pid,
65	        port: _listenPort,
66	        mode: process.env.API_DASHBOARD_PROXY_MODE ?? "standalone",
67	        uptime: Math.floor((Date.now() - _startTime) / 1000),
68	        requestCount: _requestCount,
69	      }));
70	      return;
71	    }
72	    // 明文 HTTP 代理请求（如 ANTHROPIC_BASE_URL=http://127.0.0.1:8742 的流量）。
73	    // 白名单内的 host 记录旁路；白名单外透传。
74	    handleHttpForward(req, res);
75	  });
76	
77	  proxy.on("connect", async (req, clientSock, head) => {
78	    _requestCount++;
79	    const target = req.url ?? "";
80	    const m = target.match(/^([^:]+):(\d+)$/);
81	    if (!m) {
82	      clientSock.write("HTTP/1.1 400 Bad Request\r\n\r\n");
83	      clientSock.end();
84	      return;
85	    }
86	    const host = m[1]!;
87	    const port = Number(m[2]);
88	    // 必须先 ack CONNECT，客户端才会发 TLS Client Hello。
89	    clientSock.write("HTTP/1.1 200 Connection established\r\n\r\n");
90	
91	    // A5.1: 每次 CONNECT 时读最新白名单（已支持热重载）。
92	    // 白名单条目可以是 "hostname" 或 "hostname:port" 两种格式。
93	    const wl = getMitmWhitelist();
94	    if (wl.has(host) || wl.has(`${host}:${port}`)) {
95	      try {
96	        await mitmIntercept(clientSock, head, host, port, httpServer);
97	      } catch (err) {
98	        debug("mitm intercept fail:", (err as Error).message);
99	        clientSock.destroy();
100	      }
101	    } else {
102	      handleTransparentTunnel(clientSock as net.Socket, host, port, head).catch((err) => {
103	        if (err instanceof UpstreamProxyError) {
104	          writeTraffic({ ts: new Date().toISOString(), kind: "event", msg: "tunnel_fail", sni: host, meta: { code: err.statusCode, via: err.via } });
105	        }
106	        clientSock.destroy();
107	      });
108	    }
109	  });
110	
111	  proxy.on("clientError", (e) => debug("proxy clientError:", e.message));
112	
113	  return new Promise((resolve, reject) => {
114	    (proxy as any).once("error", reject);
115	    proxy.listen(opts.port, LISTEN_HOST, () => {
116	      const addr = proxy.address();
117	      const actualPort = typeof addr === "object" && addr ? addr.port : opts.port;
118	      _listenPort = actualPort;
119	      try {
120	        writeFileSync(PATHS.portFile, String(actualPort));
121	        writeFileSync(PATHS.pidFile, String(process.pid));
122	      } catch {}
123	      writeTraffic({ ts: new Date().toISOString(), kind: "event", msg: "listening", meta: { port: actualPort, pid: process.pid } });
124	      opts.onListening?.(actualPort);
125	      resolve({
126	        close: () =>
127	          new Promise<void>((r) => {
128	            proxy.close(() => httpServer.close(() => {
129	              cleanupPidFiles();
130	              r();
131	            }));
132	          }),
133	      });
134	    });
135	  });
136	}
137	
138	function cleanupPidFiles(): void {
139	  try {
140	    if (existsSync(PATHS.pidFile) && readFileSync(PATHS.pidFile, "utf8").trim() === String(process.pid)) {
141	      unlinkSync(PATHS.pidFile);
142	    }
143	    if (existsSync(PATHS.portFile)) unlinkSync(PATHS.portFile);
144	  } catch {}
145	}
146	
147	async function mitmIntercept(clientSock: any, head: Buffer, host: string, port: number, httpServer: http.Server): Promise<void> {
148	  const { cert, key } = await issueLeaf(host);
149	  const ctx = tls.createSecureContext({ cert, key });
150	  // CONNECT ack 之后客户端通常立刻发 TLS Client Hello；如果在主入口 'connect' 事件给我们的 head 里已经有，先回灌。
151	  if (head.length > 0) clientSock.unshift(head);
152	  const tlsSock = new tls.TLSSocket(clientSock, {
153	    isServer: true,
154	    secureContext: ctx,
155	    ALPNProtocols: ["http/1.1"],
156	  } as any);
157	  (tlsSock as any)._mitmHost = host;
158	  (tlsSock as any)._mitmPort = port;
159	  tlsSock.on("error", (e) => debug("tlsSock err for", host, ":", e.message));
160	  tlsSock.once("secure", () => httpServer.emit("connection", tlsSock));
161	}
162	
163	async function handleTransparentTunnel(client: net.Socket, host: string, port: number, head: Buffer) {
164	  const upstream = await connectEgress({ host, port });
165	  if (head.length > 0) upstream.write(head);
166	  client.pipe(upstream);
167	  upstream.pipe(client);
168	  client.on("error", () => upstream.destroy());
169	  upstream.on("error", () => client.destroy());
170	  client.on("close", () => upstream.destroy());
171	  upstream.on("close", () => client.destroy());
172	}
173	
174	function handleMitmRequest(req: http.IncomingMessage, res: http.ServerResponse) {
175	  const sock = req.socket as any;
176	  const host = (sock?._mitmHost as string | undefined) || (req.headers.host?.split(":")[0] ?? "");
177	  // CONNECT 目标端口是上游真实端口。这里不能写死 443：
178	  // 自定义网关常见形态是 https://host:8742，若丢失端口会把已解密请求发到 host:443，
179	  // 网关通常返回 openresty 400，UI 看起来像"已拦截但请求坏了"。
180	  const port = Number(sock?._mitmPort ?? 443);
181	  const sni = host;
182	  const startedAt = Date.now();
183	  const origin = port === 443 ? `https://${host}` : `https://${host}:${port}`;
184	
185	  const reqHeaders: Record<string, string> = {};
186	  for (let i = 0; i < req.rawHeaders.length; i += 2) {
187	    reqHeaders[req.rawHeaders[i]!] = req.rawHeaders[i + 1]!;
188	  }
189	
190	  const reqChunks: Buffer[] = [];
191	  req.on("data", (c) => reqChunks.push(c));
192	  req.on("end", () => {
193	    const reqBody = Buffer.concat(reqChunks);
194	
195	    // A5.3: 追加用户上传的上游自签 CA（不替换系统信任链）
196	    const extraCaPems = loadTargetCaPems();
197	
198	    // 用 rawHeaders 保留原始 header name 大小写。req.headers 是 Node 标准化后的小写形式，
199	    // 某些上游网关（如企业 openresty）对 header 大小写敏感，传过去会被拒绝。
200	    const fwdHeaders: Record<string, string | string[]> = {};
201	    {
202	      const seenLower = new Set<string>();
203	      for (let i = 0; i < req.rawHeaders.length; i += 2) {
204	        const k = req.rawHeaders[i]!;
205	        const v = req.rawHeaders[i + 1]!;
206	        const lk = k.toLowerCase();
207	        if (seenLower.has(lk)) {
208	          const cur = fwdHeaders[k];
209	          if (Array.isArray(cur)) cur.push(v);
210	          else if (typeof cur === "string") fwdHeaders[k] = [cur, v];
211	          else fwdHeaders[k] = v;
212	        } else {
213	          fwdHeaders[k] = v;
214	          seenLower.add(lk);
215	        }
216	      }
217	    }
218	
219	    const proxyReq = https.request(
220	      {
221	        host,
222	        port,
223	        path: req.url,
224	        method: req.method,
225	        headers: fwdHeaders,
226	        createConnection: (_opts, cb) => {
227	          connectEgress({ host, port })
228	            .then((rawSock) => {
229	              const tlsOpts: tls.ConnectionOptions = {
230	                socket: rawSock,
231	                servername: host,
232	                ALPNProtocols: ["http/1.1"],
233	              };
234	              // A5.3: 追加用户自签 CA，保留系统根（tls.rootCertificates）。
235	              // 直接赋值 ca 会替换系统根，导致 api.anthropic.com 等公开域名 TLS 失败。
236	              if (extraCaPems.length > 0) {
237	                tlsOpts.ca = [...tls.rootCertificates, ...extraCaPems];
238	              }
239	              const t = tls.connect(tlsOpts);
240	              t.once("secureConnect", () => cb!(null, t as any));
241	              t.once("error", (e) => {
242	                // A5.4: 上游 TLS 校验失败 → 写 traffic.jsonl 事件，含证书 fingerprint
243	                const certErr = e as any;
244	                const fingerprint = certErr?.cert?.fingerprint256 ?? certErr?.cert?.fingerprint ?? "unknown";
245	                writeTraffic({
246	                  ts: new Date().toISOString(),
247	                  kind: "event",
248	                  msg: "upstream_cert_untrusted",
249	                  sni: host,
250	                  meta: {
251	                    error: e.message,
252	                    fingerprint,
253	                    hint: `如需信任此证书，将 CA PEM 放入 ${PATHS.targetCaDir}/<host>.pem`,
254	                  },
255	                });
256	                cb!(e, undefined as any);
257	              });
258	            })
259	            .catch((err) => cb!(err, undefined as any));
260	          return undefined as any;
261	        },
262	      },
263	      (proxyRes) => {
264	        res.writeHead(proxyRes.statusCode ?? 502, proxyRes.statusMessage ?? "", proxyRes.headers as any);
265	        const resHeaders: Record<string, string> = {};
266	        for (let i = 0; i < proxyRes.rawHeaders.length; i += 2) {
267	          resHeaders[proxyRes.rawHeaders[i]!] = proxyRes.rawHeaders[i + 1]!;
268	        }
269	        const resChunks: Buffer[] = [];
270	        let resBytes = 0;
271	        const isStream = (proxyRes.headers["content-type"] ?? "").includes("event-stream");
272	        // B1.1: SSE 流式解析状态
273	        const sseState = { buf: "", index: 0 };
274	        proxyRes.on("data", (c: Buffer) => {
275	          res.write(c);
276	          resBytes += c.length;
277	          if (isStream) {
278	            // B1.1: 按 SSE 事件拆行落盘，每事件一条 JSONL
279	            parseSseChunk(c.toString("utf8"), (eventType, data, idx) => {
280	              writeTraffic({
281	                ts: new Date().toISOString(),
282	                kind: "sse_event",
283	                sni,
284	                url: `${origin}${req.url}`,
285	                sseEventType: eventType,
286	                sseData: data,
287	                sseIndex: idx,
288	              });
289	            }, sseState);
290	          } else if (resBytes < 2 * 1024 * 1024) {
291	            resChunks.push(c);
292	          }
293	        });
294	        proxyRes.on("end", () => {
295	          res.end();
296	          recordUpstreamSuccess();
297	          writeTraffic({
298	            ts: new Date(startedAt).toISOString(),
299	            startedAt: new Date(startedAt).toISOString(),
300	            kind: "response",
301	            sni,
302	            method: req.method,
303	            url: `${origin}${req.url}`,
304	            status: proxyRes.statusCode,
305	            reqHeaders,
306	            resHeaders,
307	            reqBody: safeBody(reqBody),
308	            // B1.1: 流式响应记录总字节数和事件数，不再是 placeholder
309	            resBody: isStream ? `[sse ${sseState.index} events, ${resBytes} bytes]` : safeBody(Buffer.concat(resChunks)),
310	            meta: { durationMs: Date.now() - startedAt, upstream: !!process.env.API_DASHBOARD_PROXY_UPSTREAM },
311	          });
312	        });
313	        proxyRes.on("error", () => res.destroy());
314	      },
315	    );
316	    proxyReq.on("error", (err) => {
317	      const code = err instanceof UpstreamProxyError ? err.statusCode : 502;
318	      try {
319	        res.writeHead(code, { "content-type": "text/plain" });
320	        res.end(`upstream error: ${err.message}`);
321	      } catch {}
322	      recordUpstreamFailure(sni, err.message);
323	      writeTraffic({
324	        ts: new Date(startedAt).toISOString(),
325	        kind: "event",
326	        msg: "mitm_upstream_error",
327	        sni,
328	        url: `${origin}${req.url}`,
329	        meta: { error: err.message, code },
330	      });
331	    });
332	    if (reqBody.length > 0) proxyReq.write(reqBody);
333	    proxyReq.end();
334	  });
335	  req.on("error", () => res.destroy());
336	}
337	
338	// 明文 HTTP 代理转发。
339	// 处理 ANTHROPIC_BASE_URL=http://host:port 这类场景——流量不走 HTTPS CONNECT，而是直接 HTTP 请求。
340	// 白名单内的 host 记录旁路；白名单外直接透传（不记录）。
341	function handleHttpForward(req: http.IncomingMessage, res: http.ServerResponse) {
342	  // 代理请求的 URL 是绝对路径，如 http://127.0.0.1:8742/v1/messages
343	  let targetUrl: URL;
344	  try {
345	    targetUrl = new URL(req.url ?? "");
346	  } catch {
347	    res.writeHead(400);
348	    res.end("Bad Request: invalid URL");
349	    return;
350	  }
351	
352	  const host = targetUrl.hostname;
353	  const port = Number(targetUrl.port || 80);
354	  const inWhitelist = getMitmWhitelist().has(host) || getMitmWhitelist().has(`${host}:${targetUrl.port}`);
355	  const startedAt = Date.now();
356	
357	  const reqHeaders: Record<string, string> = {};
358	  for (let i = 0; i < req.rawHeaders.length; i += 2) {
359	    reqHeaders[req.rawHeaders[i]!] = req.rawHeaders[i + 1]!;
360	  }
361	
362	  const reqChunks: Buffer[] = [];
363	  req.on("data", (c) => reqChunks.push(c));
364	  req.on("end", () => {
365	    const reqBody = Buffer.concat(reqChunks);
366	
367	    // 清理代理专用 headers + transfer-encoding（我们用 content-length 替代，避免 chunked 导致目标 400）
368	    const STRIP_HEADERS = new Set(["proxy-connection", "proxy-authorization", "proxy-authenticate", "transfer-encoding"]);
369	    // 用 rawHeaders 保留客户端发的原始 header name 大小写（Host vs host）。
370	    // 某些上游网关（如企业 openresty）对 header 大小写敏感，全小写 host 会被拒绝 400。
371	    // req.headers 是 Node 标准化后的小写形式，不能直接转发。
372	    const seenLower = new Set<string>();
373	    const forwardHeaders: Record<string, string | string[]> = {};
374	    const rawHeaderOverrides = new Set(["host", "content-length", "connection"]);
375	    for (let i = 0; i < req.rawHeaders.length; i += 2) {
376	      const k = req.rawHeaders[i]!;
377	      const v = req.rawHeaders[i + 1]!;
378	      const lk = k.toLowerCase();
379	      if (STRIP_HEADERS.has(lk)) continue;
380	      if (rawHeaderOverrides.has(lk)) continue; // 我们要重写这些，下面用规范大小写
381	      if (seenLower.has(lk)) {
382	        // 同名 header 多次出现：合并为数组
383	        const cur = forwardHeaders[k];
384	        if (Array.isArray(cur)) cur.push(v);
385	        else if (typeof cur === "string") forwardHeaders[k] = [cur, v];
386	        else forwardHeaders[k] = v;
387	      } else {
388	        forwardHeaders[k] = v;
389	        seenLower.add(lk);
390	      }
391	    }
392	    // 用规范大小写写回需要覆盖的 header（Host/Content-Length/Connection）。
393	    forwardHeaders["Host"] = targetUrl.host;
394	    if (reqBody.length > 0) {
395	      forwardHeaders["Content-Length"] = String(reqBody.length);
396	    }
397	    // 强制 Connection: close，兼容不支持 HTTP/1.1 keep-alive 的目标服务（如本地 Python 网关）
398	    forwardHeaders["Connection"] = "close";
399	
400	    // 转发到目标（直连，不再走 egress 避免循环）
401	    const fwdReq = http.request(
402	      {
403	        hostname: host,
404	        port,
405	        path: targetUrl.pathname + targetUrl.search,
406	        method: req.method,
407	        headers: forwardHeaders,
408	      },
409	      (fwdRes) => {
410	        res.writeHead(fwdRes.statusCode ?? 502, fwdRes.headers as any);
411	        const resHeaders: Record<string, string> = {};
412	        for (let i = 0; i < fwdRes.rawHeaders.length; i += 2) {
413	          resHeaders[fwdRes.rawHeaders[i]!] = fwdRes.rawHeaders[i + 1]!;
414	        }
415	        const resChunks: Buffer[] = [];
416	        let resBytes = 0;
417	        const isStream = (fwdRes.headers["content-type"] ?? "").includes("event-stream");
418	        const sseState = { buf: "", index: 0 };
419	
420	        fwdRes.on("data", (c: Buffer) => {
421	          res.write(c);
422	          resBytes += c.length;
423	          if (isStream && inWhitelist) {
424	            parseSseChunk(c.toString("utf8"), (eventType, data, idx) => {
425	              writeTraffic({
426	                ts: new Date().toISOString(),
427	                kind: "sse_event",
428	                sni: host,
429	                url: req.url ?? "",
430	                sseEventType: eventType,
431	                sseData: data,
432	                sseIndex: idx,
433	              });
434	            }, sseState);
435	          } else if (!isStream && resBytes < 2 * 1024 * 1024) {
436	            resChunks.push(c);
437	          }
438	        });
439	
440	        fwdRes.on("end", () => {
441	          res.end();
442	          if (inWhitelist) {
443	            writeTraffic({
444	              ts: new Date(startedAt).toISOString(),
445	              startedAt: new Date(startedAt).toISOString(),
446	              kind: "response",
447	              sni: host,
448	              method: req.method,
449	              url: req.url ?? "",
450	              status: fwdRes.statusCode,
451	              reqHeaders,
452	              resHeaders,
453	              reqBody: safeBody(reqBody),
454	              resBody: isStream ? `[sse ${sseState.index} events, ${resBytes} bytes]` : safeBody(Buffer.concat(resChunks)),
455	              meta: { durationMs: Date.now() - startedAt, httpForward: true },
456	            });
457	          }
458	        });
459	        fwdRes.on("error", () => res.destroy());
460	      },
461	    );
462	    fwdReq.on("error", (err) => {
463	      try { res.writeHead(502); res.end(`forward error: ${err.message}`); } catch {}
464	      if (inWhitelist) {
465	        writeTraffic({
466	          ts: new Date(startedAt).toISOString(),
467	          kind: "event",
468	          msg: "http_forward_error",
469	          sni: host,
470	          url: req.url ?? "",
471	          meta: { error: err.message },
472	        });
473	      }
474	    });
475	    if (reqBody.length > 0) fwdReq.write(reqBody);
476	    fwdReq.end();
477	  });
478	  req.on("error", () => res.destroy());
479	}
480	
481	function safeBody(buf: Buffer): string {
482	  if (buf.length === 0) return "";
483	  if (buf.length > 256 * 1024) return `[truncated ${buf.length} bytes]`;
484	  const sample = buf.subarray(0, Math.min(buf.length, 64)).toString("utf8");
485	  // eslint-disable-next-line no-control-regex
486	  if (/[\x00-\x08\x0E-\x1F]/.test(sample)) return `[binary ${buf.length} bytes]`;
487	  return buf.toString("utf8");
488	}
