// 代理流量列表 + 单请求详情（lazy load）。
import { useCallback, useEffect, useRef, useState } from "react";

const T = {
  title:          { zh: "代理流量", en: "Proxy Traffic" },
  live:           { zh: "实时", en: "Live" },
